export function getDropsyAirdropErrorMessage(code: DropsyAirdropError): string {
  if (process.env.NODE_ENV !== "production") {
    return (dropsyAirdropErrorMessages as Record<DropsyAirdropError, string>)[
      code
    ];
  }

  return "Error message not available in production bundles.";
}

export function isDropsyAirdropError<
  TProgramErrorCode extends DropsyAirdropError,
>(
  error: unknown,
  transactionMessage: {
    instructions: Record<number, { programAddress: Address }>;
  },
  code?: TProgramErrorCode,
): error is SolanaError<typeof SOLANA_ERROR__INSTRUCTION_ERROR__CUSTOM> &
  Readonly<{ context: Readonly<{ code: TProgramErrorCode }> }> {
  return isProgramError<TProgramErrorCode>(
    error,
    transactionMessage,
    DROPSY_AIRDROP_PROGRAM_ADDRESS,
    code,
  );
}
